/**
 * BlockedWord
 *
 * Represents a blocked word with its action and optional description
 */
export type BlockedWord = {
    /**
     * Action to take when keyword is detected (BLOCK or MASK)
     */
    action: ContentFilterAction;
    /**
     * Description
     *
     * Optional description explaining why this keyword is sensitive
     */
    description?: string | null;
    /**
     * Keyword
     *
     * The keyword to block or mask
     */
    keyword: string;
};

/**
 * ContentFilterAction
 *
 * Action to take when content filter detects a match
 */
export type ContentFilterAction = 'BLOCK' | 'MASK';

/**
 * ContentFilterCategoryConfig
 *
 * category: "harmful_self_harm"
 * enabled: true
 * action: "BLOCK"
 * severity_threshold: "medium"
 * category_file: "/path/to/custom_file.yaml"  # optional override
 */
export type ContentFilterCategoryConfig = {
    /**
     * Action
     *
     * The action to take when the category is detected
     */
    action: 'BLOCK' | 'MASK';
    /**
     * Category
     *
     * The category to detect
     */
    category: string;
    /**
     * Category File
     *
     * Optional override. Use your own category file instead of the default one.
     */
    category_file?: string | null;
    /**
     * Enabled
     *
     * Whether the category is enabled
     */
    enabled?: boolean;
    /**
     * Severity Threshold
     *
     * The severity threshold to detect the category
     */
    severity_threshold?: 'high' | 'medium' | 'low';
    [key: string]: unknown;
};

/**
 * ContentFilterPattern
 *
 * Represents a content filter pattern (prebuilt or custom regex)
 */
export type ContentFilterPattern = {
    /**
     * Action to take when pattern matches (BLOCK or MASK)
     */
    action: ContentFilterAction;
    /**
     * Name
     *
     * Name for this pattern (used in logging and error messages)
     */
    name?: string | null;
    /**
     * Pattern
     *
     * Custom regex pattern. Required if pattern_type is 'regex'
     */
    pattern?: string | null;
    /**
     * Pattern Name
     *
     * Name of prebuilt pattern (e.g., 'us_ssn', 'credit_card'). Required if pattern_type is 'prebuilt'
     */
    pattern_name?: string | null;
    /**
     * Pattern Type
     *
     * Type of pattern: 'prebuilt' for predefined patterns or 'regex' for custom
     */
    pattern_type: 'prebuilt' | 'regex';
};

